import StyleDictionary, { type TransformedToken } from 'style-dictionary';

export type Mode = 'light' | 'dark';
export type TokensByMode = {
  [key in Mode]?: TransformedToken[];
};

/** style dictionary types are still WIP so this is a workaround to the missing Register* exports */
export type FormatConfig = Parameters<StyleDictionary['registerFormat']>[0];
export type Formatter = FormatConfig['format'];
export type FormatFnArguments = Parameters<Formatter>[0];

export type Tokens = Record<string, string>;
